 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	import { useLocation } from 'react-router-dom-v5-compat';
 4	
 5	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getVMStatus } from '@kubevirt-utils/resources/shared';
 8	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
 9	import { Popover, PopoverPosition, Text } from '@patternfly/react-core';
10	import { createURL } from '@virtualmachines/details/tabs/overview/utils/utils';
11	
12	type VirtualMachineOverviewStatusProps = {
13	  vm: V1VirtualMachine;
14	};
15	
16	const VirtualMachineOverviewStatus: FC<VirtualMachineOverviewStatusProps> = ({ children, vm }) => {
17	  const { t } = useKubevirtTranslation();
18	  const location = useLocation();
19	  const vmPrintableStatus = getVMStatus(vm);
20	
21	  if (!vmPrintableStatus) return <>{NO_DATA_DASH}</>;
22	
23	  return (
24	    <>
25	      <Popover
26	        bodyContent={
27	          <>
28	            <Text>
29	              {t('VirtualMachine is currently {{ status }}', {
30	                status: vmPrintableStatus,
31	              })}
32	            </Text>
33	            <br />
34	            <Text>
35	              <Link to={createURL('diagnostics', location?.pathname)}>{t('View diagnostic')}</Link>
36	            </Text>
37	          </>
38	        }
39	        headerContent={vmPrintableStatus}
40	        position={PopoverPosition.right}
41	      >
42	        <>{children}</>
43	      </Popover>
44	    </>
45	  );
46	};
47	
48	export default VirtualMachineOverviewStatus;

